import{t as e}from"./createLucideIcon-BKvEPEKI.js";import{i as t,r as n}from"./seo-D6pFUx3q.js";var r=e(`brush-cleaning`,[[`path`,{d:`m16 22-1-4`,key:`1ow2iv`}],[`path`,{d:`M19 13.99a1 1 0 0 0 1-1V12a2 2 0 0 0-2-2h-3a1 1 0 0 1-1-1V4a2 2 0 0 0-4 0v5a1 1 0 0 1-1 1H6a2 2 0 0 0-2 2v.99a1 1 0 0 0 1 1`,key:`iw8jdu`}],[`path`,{d:`M5 14h14l1.973 6.767A1 1 0 0 1 20 22H4a1 1 0 0 1-.973-1.233z`,key:`1soew8`}],[`path`,{d:`m8 22 1-4`,key:`s3unb`}]]),i=e(`crown`,[[`path`,{d:`M11.562 3.266a.5.5 0 0 1 .876 0L15.39 8.87a1 1 0 0 0 1.516.294L21.183 5.5a.5.5 0 0 1 .798.519l-2.834 10.246a1 1 0 0 1-.956.734H5.81a1 1 0 0 1-.957-.734L2.02 6.02a.5.5 0 0 1 .798-.519l4.276 3.664a1 1 0 0 0 1.516-.294z`,key:`1vdc57`}],[`path`,{d:`M5 21h14`,key:`11awu3`}]]),a=e(`heart-pulse`,[[`path`,{d:`M2 9.5a5.5 5.5 0 0 1 9.591-3.676.56.56 0 0 0 .818 0A5.49 5.49 0 0 1 22 9.5c0 2.29-1.5 4-3 5.5l-5.492 5.313a2 2 0 0 1-3 .019L5 15c-1.5-1.5-3-3.2-3-5.5`,key:`mvr1a0`}],[`path`,{d:`M3.22 13H9.5l.5-1 2 4.5 2-7 1.5 3.5h5.27`,key:`auskq0`}]]),o=e(`mail`,[[`path`,{d:`m22 7-8.991 5.727a2 2 0 0 1-2.009 0L2 7`,key:`132q7q`}],[`rect`,{x:`2`,y:`4`,width:`20`,height:`16`,rx:`2`,key:`izxlao`}]]),s=e(`phone`,[[`path`,{d:`M13.832 16.568a1 1 0 0 0 1.213-.303l.355-.465A2 2 0 0 1 17 15h3a2 2 0 0 1 2 2v3a2 2 0 0 1-2 2A18 18 0 0 1 2 4a2 2 0 0 1 2-2h3a2 2 0 0 1 2 2v3a2 2 0 0 1-.8 1.6l-.468.351a1 1 0 0 0-.292 1.233 14 14 0 0 0 6.392 6.384`,key:`9njp5v`}]]),c=e(`scan-search`,[[`path`,{d:`M3 7V5a2 2 0 0 1 2-2h2`,key:`aa7l1z`}],[`path`,{d:`M17 3h2a2 2 0 0 1 2 2v2`,key:`4qcy5o`}],[`path`,{d:`M21 17v2a2 2 0 0 1-2 2h-2`,key:`6vwrx8`}],[`path`,{d:`M7 21H5a2 2 0 0 1-2-2v-2`,key:`ioqczr`}],[`circle`,{cx:`12`,cy:`12`,r:`3`,key:`1v7zrd`}],[`path`,{d:`m16 16-1.9-1.9`,key:`1dq9hf`}]]),l=e(`shield-check`,[[`path`,{d:`M20 13c0 5-3.5 7.5-7.66 8.95a1 1 0 0 1-.67-.01C7.5 20.5 4 18 4 13V6a1 1 0 0 1 1-1c2 0 4.5-1.2 6.24-2.72a1.17 1.17 0 0 1 1.52 0C14.51 3.81 17 5 19 5a1 1 0 0 1 1 1z`,key:`oel41y`}],[`path`,{d:`m9 12 2 2 4-4`,key:`dzmm74`}]]),u=e(`syringe`,[[`path`,{d:`m18 2 4 4`,key:`22kx64`}],[`path`,{d:`m17 7 3-3`,key:`1w1zoj`}],[`path`,{d:`M19 9 8.7 19.3c-1 1-2.5 1-3.4 0l-.6-.6c-1-1-1-2.5 0-3.4L15 5`,key:`1exhtz`}],[`path`,{d:`m9 11 4 4`,key:`rovt3i`}],[`path`,{d:`m5 19-3 3`,key:`59f2uf`}],[`path`,{d:`m14 4 6 6`,key:`yqp9t2`}]]),d=[{slug:`dentisterie-pediatrique`,title:`Dentisterie Pédiatrique`,excerpt:`La pédodontie est la dentisterie pédiatrique, c'est-à-dire la prise en charge des enfants qui nécessitent des soins dentaires...`,image:`https://avicennedental.be/wp-content/uploads/2023/01/pedodontie-1024x435-1.jpg`,content:[`La pédodontie est la dentisterie pédiatrique, c'est-à-dire la prise en charge des enfants qui nécessitent des soins dentaires. L'accueil et la communication sont très importants en pédodontie, afin de rassurer l'enfant et de le mettre en confiance vis-à-vis des soins qui vont lui être dispensés. Si un enfant vit bien ses premiers traitements dentaires, il prendra plus facilement en charge sa santé buccodentaire tout au long de sa vie.`,`Les principales pathologies de l'enfant sont :`,`• La carie dentaire est la plus fréquente. Elle se développe plus vite chez l’enfant que chez l’adulte. Chez les tout petits, la « carie du biberon » détériore les premières dents des enfants qui boivent du lait ou du jus de fruits au coucher ou pendant la nuit.`,`• Les abcès de gencives, qui peuvent venir lors de la pousse d'une dent de lait.`,`Actuellement les soins pour les enfants et adolescents avant 18 ans sont intégralement remboursés par la mutualité. Parfois suite à un examen dentaire une visite chez l'orthodontiste s'avère nécessaire, votre dentiste pourra vous adresser chez notre orthodontiste pour un examen plus avancé.`],icon:t,metaDescription:`Dentisterie pédiatrique à Schaerbeek : soins dentaires pour enfants, accompagnement rassurant et suivi préventif.`},{slug:`caries-dentaires`,title:`Caries Dentaires`,excerpt:`On détecte les premiers symptômes de la carie dentaire à la formation de petites tâches blanches crayeuses sur la dent...`,image:`https://avicennedental.be/wp-content/uploads/2023/01/Illustrations_Dentego-carie.jpg`,content:[`On détecte les premiers symptômes de la carie dentaire à la formation de petites taches blanches crayeuses sur la dent. Une sensibilité accrue aux pressions sur une dent, au froid, aux aliment sucrés, sont également des signes annonciateurs d'une carie en train de se former. Peu à peu, une cavité se forme à la surface de l'émail de la dent. Cette cavité, si elle n'est pas traitée rapidement par un dentiste, continue de se creuser jusqu'à atteindre les nerfs de la dent. Les caries dentaires peuvent avoir des conséquences importantes sur la santé car il s'agit d'infections qui peuvent se propager rapidement.`,`Traitements caries dentaires : Pour une carie n'ayant atteint que l'émail de la dent, le dentiste l'élimine et comble le trou avec un « plombage » à base d'alliage dentaire ou de composites en résine. Les avantages de ces produits sont leur durée de séchage, très rapide et, dans le cas du « ciment composite dentaire » sa couleur proche de celle de la dent. Si la carie a atteint le nerf, la dent doit être dévitalisée. La dent cariée est nettoyée et vidée, tout en préservant l'enveloppe de la racine. Le dentiste reconstitue ensuite la forme de la dent, pour que vous puissiez retrouver son usage.`],icon:l,metaDescription:`Traitement des caries dentaires à Avicenne Dental : diagnostic précoce, restauration et soins conservateurs.`},{slug:`detartrage-dentaire`,title:`Détartrage Dentaire`,excerpt:`Le tartre dentaire est le résultat du durcissement de la plaque dentaire, qui se dépose sur la surface de la dent. Constituée de bactéries...`,image:`https://avicennedental.be/wp-content/uploads/2023/01/tartre-dentaire-illustration.jpg`,content:[`Le tartre dentaire est le résultat du durcissement de la plaque dentaire, qui se dépose sur la surface de la dent. Essentiellement constituée de bactéries, la plaque dentaire non éliminée se transforme en tartre, sépare la gencive de la racine des dents et crée un nid de bactéries favorables aux caries. Faire un détartrage régulier des dents chez son dentiste évite l'accumulation du tartre qui peut se transformer en gingivite ou même parodontale, et provoquer un déchaussement de la dent.`,`Les traitements chez le dentiste sont indolores et débarrassent l'intégralité du dépôt de tartre sur les dents, et leur rend, par la même occasion, leur couleur d'origine. Suite au détartrage des dents, le dentiste réalise un polissage de la dent. L'apparition du tartre sur les dents concerne les adultes comme les plus jeunes, c'est pourquoi il est recommandé de bien se brosser les dents 2 fois par jour. Les personnes les plus à même de faire un détartrage dentaire fréquent sont celles qui consomment des boissons comme le thé ou le café, ainsi que les fumeurs. Même s'il est recommandé de faire un détartrage au moins une fois par an, cela peut varier d'une personne à une autre. Suivez les conseils de votre dentiste qui, après un examen bucco-dentaire, sera le mieux placé pour vous dire quoi faire.`],icon:r,metaDescription:`Détartrage dentaire professionnel à Schaerbeek pour prévenir tartre, gingivite et inconfort gingival.`},{slug:`endodontie`,title:`Endodontie`,excerpt:`L'endodontie consiste à dévitaliser la dent. Lorsqu'une carie est trop profonde et que le nerf est touché, il est impératif de nettoyer les racines de la dent.`,image:`https://avicennedental.be/wp-content/uploads/2023/01/WhatsApp-Image-2023-01-10-at-21.31.39-1024x385.jpeg`,content:[`L'endodontie consiste à dévitaliser la dent. Lorsqu'une carie est trop profonde et que le nerf est touché, il est impératif de nettoyer les racines de la dent, il faut alors la dévitaliser pour éviter une infection dentaire. Une fois le nerf retiré, la dent est reconstruite. Il est possible de couronner la dent par la suite.`],icon:a,metaDescription:`Endodontie et dévitalisation à Avicenne Dental pour traiter une infection profonde et préserver la dent.`},{slug:`protheses-amovibles`,title:`Prothèses Dentaires Amovibles`,excerpt:`La prothèse dentaire amovible, couramment appelée dentier, peut remplacer une ou plusieurs dents et se retirer en fonction des besoins du patient...`,image:`https://avicennedental.be/wp-content/uploads/2023/01/protheses-dentaires-amovibles-1024x342.jpg`,images:[`https://avicennedental.be/wp-content/uploads/2023/01/protheses-dentaires-amovibles-1024x342.jpg`,`https://avicennedental.be/wp-content/uploads/2023/01/prothese-amovible-complete.jpg`,`https://avicennedental.be/wp-content/uploads/2023/01/implant-amovible-partiel-double.jpg`],content:[`La prothèse dentaire amovible, couramment appelée dentier, peut remplacer une ou plusieurs dents et peut se placer ou se retirer en fonction des besoins du patient. On en distingue deux types : les prothèses dentaires amovibles partielles et les prothèses dentaires amovibles complètes.`,`Ces prothèses amovibles doivent être retirées et nettoyées à la fin de chaque repas. Ce type de prothèse est amovible et encombrante, mais elle a cependant l'avantage d'être économique et rapide à réaliser. Cette prothèse est facilement réparable et évolutive comme dans le cas d'une perte supplémentaire d'une dent, la dentition peut être complétée par adjonction sur le même appareil. Elles sont parfois utilisées comme prothèses provisoires pour pallier l'absence de dents en attendant la conception d'une prothèse fixe comme un bridge dentaire. En fonction des cas, votre dentiste vous conseillera de manière adaptée.`],sections:[{title:`PROTHÈSE AMOVIBLE PARTIELLE`,image:`https://avicennedental.be/wp-content/uploads/2023/01/prothese-amovible-complete.jpg`}],icon:i,metaDescription:`Prothèses dentaires amovibles partielles ou complètes pour remplacer une ou plusieurs dents avec confort.`},{slug:`blanchiment-dentaire`,title:`Blanchiment Dentaire`,excerpt:`Ces techniques sont réservées à des cas particuliers, et ne doivent surtout pas servir de prétexte à une mauvaise hygiène bucco-dentaire...`,image:`https://avicennedental.be/wp-content/uploads/2023/01/blanchiment-dentaire-apres-1024x551.jpg`,content:[`Le blanchiment dentaire permet d'éclaircir la teinte des dents. La coloration des dents est influencée par différents éléments :`,`• l'hérédité`,`• la prise de certains médicaments pendant la période de formation de la dent.`,`• le mode de vie : consommation de café, thé, tabac, vin…`,`Avant de commencer un traitement de blanchiment dentaire, le praticien établira un bilan buccodentaire. Ainsi, l'on vérifiera qu'il n'y a pas de contre-indications au traitement : caries, maladies, parodontales…`,`Gouttières ambulatoires : Le praticien prend une empreinte de la bouche, confectionne des gouttières, qui seront appliquées toutes les nuits durant environ deux semaines. Le patient insère le gel blanchissant dans la gouttière, et la porte pendant un temps défini par le praticien.`],icon:n,metaDescription:`Blanchiment dentaire encadré par votre dentiste pour éclaircir la teinte des dents en toute sécurité.`},{slug:`orthodontie`,title:`Orthodontie`,excerpt:`L'orthodontie consiste à corriger les malpositions et encombrements dentaires. Au delà de l'aspect esthétique, la phonation...`,image:`https://avicennedental.be/wp-content/uploads/2023/01/ortho-1024x512.jpg`,content:[`L'orthodontie consiste à corriger les malpositions et encombrements dentaires. Au-delà de l'aspect esthétique, d'autres fonctions comme la phonation, la mastication et respiration peuvent être rétablies. Pour les jeunes comme pour les adultes il est parfois difficile d'accepter un traitement en orthodontie. Les dispositifs « multi attaches » traditionnellement en acier, peuvent se faire en céramique et sont donc plus discret.`,`La technique invisible par gouttière Invisalign est aussi en plein essor et est très appréciée par les patients avec une forte demande esthétique. Renseignez-vous auprès de notre orthodontiste qui vous conseillera le traitement le plus adapté à votre cas. De manière général c'est souvent votre dentiste qui vous orientera vers l'orthodontiste. Pour les jeunes patients le traitement doit être démarré avant l'âge de 15 ans pour bénéficier du remboursement partiel de la mutualité. Certains appareils doivent être placés avant l'âge de 8 ans pour avoir un remboursement partiel (ex : les disjoncteurs).`],icon:c,metaDescription:`Orthodontie pour enfants et adultes, appareils classiques, céramiques ou solutions plus discrètes.`},{slug:`protheses-fixes`,title:`Prothèses Dentaires Fixes`,excerpt:`Les prothèses dentaires fixes remplacent soit une partie de dent, soit une ou plusieurs dents, de façon permanente...`,image:`https://avicennedental.be/wp-content/uploads/2023/01/Couronne-dentaire-1024x939-1.jpg`,images:[`https://avicennedental.be/wp-content/uploads/2023/01/Couronne-dentaire-1024x939-1.jpg`,`https://avicennedental.be/wp-content/uploads/2023/01/bridge-implant-1024x837.jpg`,`https://avicennedental.be/wp-content/uploads/2023/01/Porcelain-Inlays-and-Onlays2-1024x560.jpg`],content:[`Les prothèses dentaires fixes remplacent soit une partie de dent, soit une ou plusieurs dents, de façon permanente. Elles permettent de retrouver l'esthétisme d'un sourire naturel et les fonctions masticatoires sans avoir à les retirer pour l'entretien. Il n'existe donc aucun inconvénient en termes d'hygiène.`,`Il existe plusieurs types de prothèses dentaires :`,`• Les couronnes pour remplacer l’ensemble de la partie visible de la dent en la recouvrant et la solidifiant.`,`• Les bridges pour remplacer une ou plusieurs dents manquantes.`,`• Les onlays/inlays qui consistent en une couronne partielle de la dent.`,`Les onglets ci-dessous détaillent ces différents types de prothèses dentaires fixes pour que vous soyez informés le mieux possible. N'hésitez pas à prendre rendez-vous avec un de nos spécialistes dentaires qui, après une consultation, pourra évaluer vos besoins. Vous aurez ainsi au préalable un devis transparent avec le prix de la prothèse dentaire fixe qui vous est adaptée.`],sections:[{title:`COURONNE`,image:`https://avicennedental.be/wp-content/uploads/2023/01/Couronne-dentaire-1024x939-1.jpg`},{title:`BRIDGE`,image:`https://avicennedental.be/wp-content/uploads/2023/01/bridge-implant-1024x837.jpg`},{title:`INLAY-ONLAY`,image:`https://avicennedental.be/wp-content/uploads/2023/01/Porcelain-Inlays-and-Onlays2-1024x560.jpg`}],icon:i,metaDescription:`Couronnes, bridges et inlays-onlays pour restaurer durablement les dents avec une solution fixe.`},{slug:`implant-dentaire`,title:`Implant Dentaire`,excerpt:`La pose d'un implant dentaire est un acte médical simple, réalisé sous anesthésie locale, pour remplacer une ou plusieurs dents manquantes...`,image:`https://avicennedental.be/wp-content/uploads/2023/01/structure-implant-dentaire.jpg`,content:[`La pose d'un implant dentaire est un acte médical simple, réalisé sous anesthésie locale, pour remplacer une ou plusieurs dents manquantes, tout en préservant les dents saines à proximité. Le principe repose sur une racine artificielle qui permettra à la couronne dentaire ou la prothèse de se fixer. La pose se déroule en deux temps. Lors de la première opération, le chirurgien-dentiste incise la gencive à l'endroit où sera placé l'implant. Ce dernier est vissé au niveau de la racine de la dent. Après quelques mois de cicatrisation, une seconde opération consiste à mettre en place la dent artificielle, une couronne, un bridge ou une prothèse. Les implants dentaires ont démontré leur efficacité, leur innocuité vis-à-vis des autres dents, leur durée de vie et la qualité du résultat esthétique. Le prix d'une chirurgie dentaire par implant varie en fonction du nombre de dents à remplacer. Un devis transparent vous sera réalisé avant le traitement.`],icon:u,metaDescription:`Implant dentaire à Schaerbeek pour remplacer une ou plusieurs dents avec stabilité et esthétique durable.`}],f=Object.fromEntries(d.map(e=>[e.slug,e]));export{o as a,s as i,f as n,l as r,d as t};